// Extract the Attio deal record id. Handles every shape we might receive:
//  - Attio NATIVE webhook (Developers > Webhooks): { events: [ { id: { record_id } } ] }
//  - flat { attio_deal_id } (manual curl test)
//  - { record: {...} } wrapper, or a raw Attio record object
const j = $input.first().json;
const body = (j.body !== undefined && j.body !== null) ? j.body : j;
let dealId = null;
// Attio native webhook payload — events array
if (body.events && Array.isArray(body.events) && body.events[0] && body.events[0].id) {
  dealId = body.events[0].id.record_id || body.events[0].id;
}
// Flat / wrapper shapes
if (!dealId) {
  dealId = body.attio_deal_id || body.attioDealId || body.deal_id || body.id;
  if (dealId && typeof dealId === 'object') {
    dealId = dealId.record_id || dealId.id || null;
  }
}
if (!dealId && body.record && body.record.id) {
  dealId = body.record.id.record_id || body.record.id;
}
if (!dealId || typeof dealId !== 'string') {
  throw new Error('Could not extract attio_deal_id from payload: ' + JSON.stringify(j).slice(0, 400));
}
dealId = dealId.trim();
if (!dealId) {
  throw new Error('attio_deal_id was empty after trimming: ' + JSON.stringify(j).slice(0, 400));
}
return [{ json: { attio_deal_id: dealId } }];

// STAGE GATE — Attio's native webhook fires on every deal update, so only
// proceed when the deal is at stage 'Onboarded' AND has no FirstPromoter code
// yet. Returning [] stops the workflow quietly: no error, no downstream nodes.
const deal = $('Fetch Attio Deal').first().json;
const dv = (deal.data && deal.data.values) || {};
const stage = ((dv.stage && dv.stage[0] && dv.stage[0].status && dv.stage[0].status.title) || '').trim();
const existingCode = (dv.firstpromoter_code && dv.firstpromoter_code[0] && dv.firstpromoter_code[0].value) || '';
if (stage !== 'Onboarded' || existingCode) {
  return [];
}
// Build the FirstPromoter payload from the linked Person.
const person = $input.first().json;
const v = (person.data && person.data.values) || {};
const email = (v.email_addresses && v.email_addresses[0] && v.email_addresses[0].email_address) || '';
const nameObj = (v.name && v.name[0]) || {};
const dealId = $('Format Input').first().json.attio_deal_id;
if (!email) {
  throw new Error('Linked Person has no email address — cannot create a FirstPromoter promoter.');
}
return [{ json: {
  attio_deal_id: dealId,
  email: email,
  first_name: nameObj.first_name || '',
  last_name: nameObj.last_name || ''
}}];
